// Block catalog. Reads the real package files via Vite ?raw imports so the
// gallery always reflects blocks/ on disk. As the catalog grows this can be
// generated by `auto block export-gallery-meta` (Plan 343); for the seed set
// it's a small manifest.

import loginSpec from '../../../blocks/form/login/spec.md?raw'
import loginGotchas from '../../../blocks/form/login/gotchas.md?raw'
import loginMinimal from '../../../blocks/form/login/reference/minimal.at?raw'
import loginSso from '../../../blocks/form/login/reference/with_sso.at?raw'

import noteListSpec from '../../../blocks/data-display/note-list/spec.md?raw'
