export interface BlockEntry {
  kind: string
  name: string
  spec: string
  gotchas: string
  references: Record<string, string>
}

export const blocks: BlockEntry[] = [
  {
    kind: 'form',
    name: 'login',
    spec: loginSpec,
    gotchas: loginGotchas,
    references: { minimal: loginMinimal, with_sso: loginSso },
  },
  {
    kind: 'data-display',
    name: 'note-list',
    spec: noteListSpec,
    gotchas: noteListGotchas,
    references: { default: noteListDefault },
  },
]

export const kindOrder = ['form', 'data-display', 'feedback', 'layout', 'composite']
